CREATE CACHED TABLE "PUBLIC"."SALE_ITEMS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 37) NOT NULL,
    "QUANTITY" INTEGER,
    "SUBTOTAL" NUMERIC(38, 2),
    "UNIT_PRICE" NUMERIC(38, 2),
    "PRODUCT_ID" BIGINT,
    "SALE_ID" BIGINT
