ALTER TABLE "PUBLIC"."SALE_ITEMS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_9" PRIMARY KEY("ID");   
-- 21 +/- SELECT COUNT(*) FROM PUBLIC.SALE_ITEMS;             
CREATE CACHED TABLE "PUBLIC"."SALES"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 37) NOT NULL,
    "DISCOUNT" NUMERIC(38, 2),
    "FINAL_AMOUNT" NUMERIC(38, 2),
    "NOTES" CHARACTER VARYING(255),
    "PAYMENT_METHOD" CHARACTER VARYING(255),
    "SALE_DATE" TIMESTAMP(6),
    "STATUS" CHARACTER VARYING(255),
    "TOTAL_AMOUNT" NUMERIC(38, 2),
    "CUSTOMER_ID" BIGINT
); 
ALTER TABLE "PUBLIC"."SALES" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_4" PRIMARY KEY("ID");        
